import { DustAddress } from '@midnight-ntwrk/wallet-sdk-address-format';
export const makeDefaultKeysCapability = () => {
    return {
        getPublicKey: (state) => {
            return state.publicKey.publicKey;
        },
        getAddress: (state) => {
            return new DustAddress(state.publicKey.publicKey);
        },
    };
};
